class Solution:
    def countGoodIntegers(self, n: int, k: int) -> int:
        MOD = 10**9 + 7
        res = 0
        for i in range(1, 10):
            if k % i == 0:
                res += self.dfs(i, n - 1, k, MOD)
        return res

    def dfs(self, cur, left, k, MOD):
        if left == 0:
            return 1
        res = 0
        for i in range(10):
            if i != cur % 10:
                res += self.dfs(i, left - 1, k, MOD)
        return res % MOD
```

